import{_ as a,c as s,o,a1 as i}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"阶段 1：Bootstrap - 结构化产品想法 | Agent App Factory 教程","description":"学习 Bootstrap 阶段如何将模糊的产品想法转化为清晰、结构化的 input/idea.md 文档。本教程讲解 Bootstrap Agent 的职责、superpowers:brainstorm 技能的使用、idea.md 的标准结构和质量检查清单。","frontmatter":{"title":"阶段 1：Bootstrap - 结构化产品想法 | Agent App Factory 教程","sidebarTitle":"结构化产品想法","subtitle":"阶段 1：Bootstrap - 结构化产品想法","description":"学习 Bootstrap 阶段如何将模糊的产品想法转化为清晰、结构化的 input/idea.md 文档。本教程讲解 Bootstrap Agent 的职责、superpowers:brainstorm 技能的使用、idea.md 的标准结构和质量检查清单。","tags":["流水线","Bootstrap","产品想法"],"prerequisite":["start-pipeline-overview"],"order":80},"headers":[],"relativePath":"zh/hyz1992/agent-app-factory/advanced/stage-bootstrap/index.md","filePath":"zh/hyz1992/agent-app-factory/advanced/stage-bootstrap/index.md"}'),e={name:"zh/hyz1992/agent-app-factory/advanced/stage-bootstrap/index.md"};function l(r,t,n,p,d,h){return o(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="阶段-1-bootstrap-结构化产品想法" tabindex="-1">阶段 1：Bootstrap - 结构化产品想法 <a class="header-anchor" href="#阶段-1-bootstrap-结构化产品想法" aria-label="Permalink to &quot;阶段 1：Bootstrap - 结构化产品想法&quot;">​</a></h1><p>Bootstrap 是 Agent App Factory 流水线的第一个阶段，负责将你模糊的产品想法整理成清晰的 <code>input/idea.md</code> 文档。这是后续 PRD、UI、Tech 等所有阶段的起点，决定了整个项目的方向和质量。</p><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>将模糊的产品想法整理为符合标准模板的 <code>input/idea.md</code> 文档</li><li>理解 Bootstrap Agent 的职责边界（只收集信息，不创造需求）</li><li>知道如何使用 superpowers:brainstorm 技能深入挖掘产品想法</li><li>能够判断什么信息应该包含在 Bootstrap 阶段，什么不该包含</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你可能有一个产品想法，但描述得很模糊：</p><ul><li>&quot;我想做一个健身应用&quot;（太泛）</li><li>&quot;做一个像小红书一样的应用&quot;（没说差异化）</li><li>&quot;用户需要一个更好的任务管理工具&quot;（没说具体问题）</li></ul><p>这种模糊的描述会导致后续阶段（PRD、UI、Tech）缺乏明确的输入，最终生成的应用可能完全偏离你的预期。</p><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><p>当你准备好启动流水线，并且满足以下条件时：</p><ol><li><strong>有一个初步的产品想法</strong>（哪怕只是一句话）</li><li><strong>还没开始写需求文档</strong>（PRD 在后续阶段）</li><li><strong>还没决定技术栈或 UI 风格</strong>（这些在后续阶段）</li><li><strong>希望控制产品范围，避免过度设计</strong>（Bootstrap 阶段会明确非目标）</li></ol><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前置条件</p><p>在开始 Bootstrap 阶段前，请确保：</p><ul><li>✅ 已完成 <a href="./../../start/init-project/">项目初始化</a></li><li>✅ 已了解 <a href="./../../start/pipeline-overview/">7 阶段流水线概览</a></li><li>✅ 已安装并配置好 AI 助手（推荐 Claude Code）</li><li>✅ 已准备好你的产品想法（哪怕是模糊的）</li></ul></div><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><h3 id="什么是-bootstrap-阶段" tabindex="-1">什么是 Bootstrap 阶段？ <a class="header-anchor" href="#什么是-bootstrap-阶段" aria-label="Permalink to &quot;什么是 Bootstrap 阶段？&quot;">​</a></h3><p><strong>Bootstrap</strong> 是整个流水线的起点，它的唯一职责是<strong>将碎片化的产品想法整理为结构化的文档</strong>。</p><div class="info custom-block"><p class="custom-block-title">不是产品经理</p><p>Bootstrap Agent 不是产品经理，它不会替你创造需求或设计功能。它的任务是：</p><ul><li>收集你已经提供的信息</li><li>梳理并组织这些信息</li><li>按照标准模板呈现</li></ul><p>它不会决定&quot;应该有什么功能&quot;，只会帮你把&quot;你想要什么&quot;说清楚。</p></div><h3 id="为什么要结构化" tabindex="-1">为什么要结构化？ <a class="header-anchor" href="#为什么要结构化" aria-label="Permalink to &quot;为什么要结构化？&quot;">​</a></h3><p>想象一下，你告诉厨师：&quot;我想吃点好吃的&quot;</p><ul><li>❌ 模糊的描述：厨师只能猜测，可能做出你完全不想吃的菜</li><li>✅ 结构化的描述：&quot;我想要一道辣的、不放香菜的川菜，希望能下饭&quot;</li></ul><p>Bootstrap 阶段就是把&quot;我想吃点好吃的&quot;变成&quot;辣的、不放香菜的川菜&quot;。</p><h3 id="输出文档结构" tabindex="-1">输出文档结构 <a class="header-anchor" href="#输出文档结构" aria-label="Permalink to &quot;输出文档结构&quot;">​</a></h3><p>Bootstrap 阶段会生成 <code>input/idea.md</code>，包含以下章节：</p><table tabindex="0"><thead><tr><th>章节</th><th>内容</th><th>示例</th></tr></thead><tbody><tr><td><strong>简要描述</strong></td><td>1-2 句话概括产品</td><td>&quot;一个移动端记账应用，帮助年轻人快速记录日常支出&quot;</td></tr><tr><td><strong>问题 (Problem)</strong></td><td>用户遇到的核心痛点</td><td>&quot;年轻人月底发现超支，但不知道钱花在哪&quot;</td></tr><tr><td><strong>目标用户 (Target User)</strong></td><td>具体的人群画像</td><td>&quot;18-30 岁刚工作的年轻人，技术能力中等&quot;</td></tr><tr><td><strong>核心价值 (Core Value)</strong></td><td>为什么有价值</td><td>&quot;3 秒记账，比手动查询节省 80% 时间&quot;</td></tr><tr><td><strong>假设 (Assumptions)</strong></td><td>2-4 条可验证的假设</td><td>&quot;用户愿意花 2 分钟学习应用，如果能控制预算&quot;</td></tr><tr><td><strong>非目标 (Non‑Goals)</strong></td><td>明确不做什么</td><td>&quot;不做预算规划和财务建议&quot;</td></tr></tbody></table><h2 id="跟我操作" tabindex="-1">跟我操作 <a class="header-anchor" href="#跟我操作" aria-label="Permalink to &quot;跟我操作&quot;">​</a></h2><h3 id="第-1-步-准备你的产品想法" tabindex="-1">第 1 步：准备你的产品想法 <a class="header-anchor" href="#第-1-步-准备你的产品想法" aria-label="Permalink to &quot;第 1 步：准备你的产品想法&quot;">​</a></h3><p>在开始流水线前，先想清楚你的产品想法。可以是一个完整的描述，也可以只是一个简单的想法。</p><p><strong>示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我想做一个健身应用，帮助健身新手记录训练，包括运动类型、时长、卡路里，还能查看本周统计。</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">想法可以很粗糙</p><p>哪怕只是一句话也没关系，Bootstrap Agent 会通过 superpowers:brainstorm 技能帮你补充完整信息。</p></div><h3 id="第-2-步-启动流水线到-bootstrap-阶段" tabindex="-1">第 2 步：启动流水线到 Bootstrap 阶段 <a class="header-anchor" href="#第-2-步-启动流水线到-bootstrap-阶段" aria-label="Permalink to &quot;第 2 步：启动流水线到 Bootstrap 阶段&quot;">​</a></h3><p>在 Factory 项目目录中执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 启动流水线（如果还没启动）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或直接指定从 bootstrap 开始</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bootstrap</span></span></code></pre></div><p>CLI 会显示当前状态和可用阶段。</p><h3 id="第-3-步-ai-助手读取-bootstrap-agent-定义" tabindex="-1">第 3 步：AI 助手读取 Bootstrap Agent 定义 <a class="header-anchor" href="#第-3-步-ai-助手读取-bootstrap-agent-定义" aria-label="Permalink to &quot;第 3 步：AI 助手读取 Bootstrap Agent 定义&quot;">​</a></h3><p>AI 助手（如 Claude Code）会自动读取 <code>agents/bootstrap.agent.md</code>，了解其职责和约束。</p><div class="info custom-block"><p class="custom-block-title">Agent 职责</p><p>Bootstrap Agent 只能：</p><ul><li>读取用户在对话中提供的产品想法</li><li>写入 <code>input/idea.md</code></li></ul><p>它不能：</p><ul><li>读取其他文件</li><li>写入其他目录</li><li>创造新需求</li></ul></div><h3 id="第-4-步-强制使用-superpowers-brainstorm-技能" tabindex="-1">第 4 步：强制使用 superpowers:brainstorm 技能 <a class="header-anchor" href="#第-4-步-强制使用-superpowers-brainstorm-技能" aria-label="Permalink to &quot;第 4 步：强制使用 superpowers:brainstorm 技能&quot;">​</a></h3><p>这是 Bootstrap 阶段的关键步骤。AI 助手<strong>必须</strong>先调用 <code>superpowers:brainstorm</code> 技能，即使你认为信息已经很完整。</p><p><strong>brainstorm 技能的作用</strong>：</p><ol><li><strong>深入挖掘问题本质</strong>：通过结构化提问发现你描述中的盲点</li><li><strong>明确目标用户画像</strong>：帮你想清楚&quot;到底卖给谁&quot;</li><li><strong>验证核心价值</strong>：通过对比竞品找到差异化</li><li><strong>识别隐含假设</strong>：列出那些你默认但未经验证的假设</li><li><strong>控制产品范围</strong>：通过非目标明确边界</li></ol><p><strong>AI 助手会做什么</strong>：</p><ul><li>调用 <code>superpowers:brainstorm</code> 技能</li><li>提供你的原始想法</li><li>通过技能生成的问题向你提问</li><li>收集你的回答并完善想法</li></ul><div class="danger custom-block"><p class="custom-block-title">跳过此步骤会被拒绝</p><p>Sisyphus 调度器会验证是否使用了 brainstorm 技能。如果没有，Bootstrap Agent 生成的产物会被拒绝，需要重新执行。</p></div><h3 id="第-5-步-确认-idea-md-内容" tabindex="-1">第 5 步：确认 idea.md 内容 <a class="header-anchor" href="#第-5-步-确认-idea-md-内容" aria-label="Permalink to &quot;第 5 步：确认 idea.md 内容&quot;">​</a></h3><p>Bootstrap Agent 完成后，会生成 <code>input/idea.md</code>。你需要仔细检查：</p><p><strong>检查点 ✅</strong>：</p><ol><li><p><strong>简要描述</strong>是否清晰？</p><ul><li>✅ 包含：做什么 + 为谁做 + 解决什么问题</li><li>❌ 太泛：&quot;一个提高效率的工具&quot;</li></ul></li><li><p><strong>问题描述</strong>是否具体？</p><ul><li>✅ 包含：场景 + 困难 + 负面结果</li><li>❌ 空泛：&quot;用户体验不好&quot;</li></ul></li><li><p><strong>目标用户</strong>是否明确？</p><ul><li>✅ 有具体画像（年龄/职业/技术能力）</li><li>❌ 模糊：&quot;所有人&quot;</li></ul></li><li><p><strong>核心价值</strong>是否可量化？</p><ul><li>✅ 有具体收益（节省 80% 时间）</li><li>❌ 空泛：&quot;提升效率&quot;</li></ul></li><li><p><strong>假设</strong>是否可验证？</p><ul><li>✅ 可通过用户调研验证</li><li>❌ 主观判断：&quot;用户会喜欢&quot;</li></ul></li><li><p><strong>非目标</strong>是否充分？</p><ul><li>✅ 至少列出 3 项不做的功能</li><li>❌ 缺失或太少</li></ul></li></ol><h3 id="第-6-步-选择继续、重试或暂停" tabindex="-1">第 6 步：选择继续、重试或暂停 <a class="header-anchor" href="#第-6-步-选择继续、重试或暂停" aria-label="Permalink to &quot;第 6 步：选择继续、重试或暂停&quot;">​</a></h3><p>确认无误后，CLI 会显示选项：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">请选择操作：</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[1] 继续（进入 PRD 阶段）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[2] 重试（重新生成 idea.md）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[3] 暂停（稍后继续）</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">建议先在代码编辑器中查看</p><p>在 AI 助手中确认前，先用代码编辑器打开 <code>input/idea.md</code>，逐字检查。一旦进入 PRD 阶段，修改成本会更高。</p></div><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="坑-1-想法描述太模糊" tabindex="-1">坑 1：想法描述太模糊 <a class="header-anchor" href="#坑-1-想法描述太模糊" aria-label="Permalink to &quot;坑 1：想法描述太模糊&quot;">​</a></h3><p><strong>错误示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我想做一个健身应用</span></span></code></pre></div><p><strong>后果</strong>：Bootstrap Agent 会通过 brainstorm 技能问很多问题，补充信息。</p><p><strong>建议</strong>：一开始就描述清楚：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我想做一个移动端健身应用，帮助健身新手记录训练，包括运动类型、时长、卡路里，还能查看本周统计。</span></span></code></pre></div><h3 id="坑-2-包含技术实现细节" tabindex="-1">坑 2：包含技术实现细节 <a class="header-anchor" href="#坑-2-包含技术实现细节" aria-label="Permalink to &quot;坑 2：包含技术实现细节&quot;">​</a></h3><p><strong>错误示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我希望使用 React Native 构建，后端用 Express，数据库是 Prisma...</span></span></code></pre></div><p><strong>后果</strong>：Bootstrap Agent 会拒绝这些内容（它只收集产品想法，技术栈在 Tech 阶段决定）。</p><p><strong>建议</strong>：只说&quot;做什么&quot;，不说&quot;怎么做&quot;。</p><h3 id="坑-3-目标用户描述太泛" tabindex="-1">坑 3：目标用户描述太泛 <a class="header-anchor" href="#坑-3-目标用户描述太泛" aria-label="Permalink to &quot;坑 3：目标用户描述太泛&quot;">​</a></h3><p><strong>错误示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>所有需要健身的人</span></span></code></pre></div><p><strong>后果</strong>：后续阶段无法明确设计方向。</p><p><strong>建议</strong>：明确画像：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>18-30 岁健身新手，刚开始系统训练，技术能力中等，希望简单记录和查看统计。</span></span></code></pre></div><h3 id="坑-4-非目标缺失或太少" tabindex="-1">坑 4：非目标缺失或太少 <a class="header-anchor" href="#坑-4-非目标缺失或太少" aria-label="Permalink to &quot;坑 4：非目标缺失或太少&quot;">​</a></h3><p><strong>错误示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>非目标：无</span></span></code></pre></div><p><strong>后果</strong>：后续 PRD 和 Code 阶段可能过度设计，增加技术复杂度。</p><p><strong>建议</strong>：至少列出 3 项：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>非目标：</span></span>
<span class="line"><span>- 团队协作和社交功能（MVP 聚焦个人）</span></span>
<span class="line"><span>- 复杂的数据分析和报表</span></span>
<span class="line"><span>- 与第三方健身设备集成</span></span></code></pre></div><h3 id="坑-5-假设不可验证" tabindex="-1">坑 5：假设不可验证 <a class="header-anchor" href="#坑-5-假设不可验证" aria-label="Permalink to &quot;坑 5：假设不可验证&quot;">​</a></h3><p><strong>错误示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>假设：用户会喜欢我们的设计</span></span></code></pre></div><p><strong>后果</strong>：无法通过用户调研验证，MVP 可能失败。</p><p><strong>建议</strong>：写可验证的假设：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>假设：用户愿意花 5 分钟学习应用，如果能帮助系统记录训练。</span></span></code></pre></div><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>Bootstrap 阶段的核心是<strong>结构化</strong>：</p><ol><li><strong>输入</strong>：你模糊的产品想法</li><li><strong>过程</strong>：AI 助手通过 superpowers:brainstorm 技能深入挖掘</li><li><strong>输出</strong>：符合标准模板的 <code>input/idea.md</code></li><li><strong>验证</strong>：检查描述是否具体、用户是否明确、价值是否可量化</li></ol><div class="tip custom-block"><p class="custom-block-title">关键原则</p><ul><li>❌ 不做什么：不创造需求、不设计功能、不决定技术栈</li><li>✅ 只做什么：收集信息、梳理组织、按模板呈现</li></ul></div><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../stage-prd/">阶段 2：PRD - 生成产品需求文档</a></strong>。</p><p>你会学到：</p><ul><li>如何将 idea.md 转化为 MVP 级 PRD</li><li>PRD 包含哪些内容（用户故事、功能列表、非功能需求）</li><li>如何明确 MVP 范围和优先级</li><li>为什么 PRD 不能包含技术细节</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>Bootstrap Agent 定义</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/bootstrap.agent.md" target="_blank" rel="noreferrer"><code>agents/bootstrap.agent.md</code></a></td><td>1-93</td></tr><tr><td>Bootstrap Skill</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/skills/bootstrap/skill.md" target="_blank" rel="noreferrer"><code>skills/bootstrap/skill.md</code></a></td><td>1-433</td></tr><tr><td>流水线定义（Bootstrap 阶段）</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/pipeline.yaml" target="_blank" rel="noreferrer"><code>pipeline.yaml</code></a></td><td>8-18</td></tr><tr><td>调度器定义</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>1-100+</td></tr></tbody></table><p><strong>关键约束</strong>：</p><ul><li><strong>强制使用 brainstorm 技能</strong>：bootstrap.agent.md:70-71</li><li><strong>禁止技术细节</strong>：bootstrap.agent.md:47</li><li><strong>禁止合并多个想法</strong>：bootstrap.agent.md:48</li><li><strong>输出文件必须保存到 input/idea.md</strong>：bootstrap.agent.md:50</li></ul><p><strong>退出条件</strong>（pipeline.yaml:15-18）：</p><ul><li>idea.md 存在</li><li>idea.md 描述了一个连贯的产品想法</li><li>Agent 已使用 <code>superpowers:brainstorm</code> 技能进行深入挖掘</li></ul><p><strong>Skill 内容框架</strong>：</p><ul><li><strong>思维框架</strong>：提取 vs 创造、问题优先、具体化、假设验证</li><li><strong>提问模板</strong>：关于问题、目标用户、核心价值、MVP 假设、非目标</li><li><strong>信息提取技巧</strong>：从功能反推问题、从抱怨提取需求、识别隐含假设</li><li><strong>质量检查清单</strong>：完整性、具体性、一致性、禁止项</li><li><strong>决策原则</strong>：优先提问、问题导向、具体优于抽象、可验证性、范围控制</li><li><strong>常见场景处理</strong>：用户只提供一句话、描述很多功能、描述竞品、想法矛盾</li><li><strong>示例对比</strong>：不好的 idea.md vs 好的 idea.md</li></ul></details>`,91)])])}const u=a(e,[["render",l]]);export{g as __pageData,u as default};
